    const options = [
      $json.contentSnippet,
      $json.content,
      $json['content:encodedSnippet'],
      $json['content:encoded']
    ];

    // Filtra valores não nulos/vazios, remove tags HTML e obtém o maior conteúdo limpo
    const longestContent = options
      .filter(text => text && typeof text === 'string') // Remove valores vazios ou não strings
      .map(text => text.removeTags()) // Remove tags HTML antes de comparar
      .reduce((max, current) => current.length > max.length ? current : max, "");

    // Retorna o maior conteúdo já limpo
    return longestContent;
  })()
}}

={{
  (() => {
    const minWords = 300; // Definir número mínimo de palavras para considerar como conteúdo válido
    const options = [
      $json.contentSnippet,
      $json.content,
      $json['content:encodedSnippet'],
      $json['content:encoded']
    ];

    // Filtra valores não nulos ou vazios e obtém o maior em termos de comprimento
    const longestContent = options
      .filter(text => text && typeof text === 'string') // Remove valores vazios ou não strings
      .reduce((max, current) => current.length > max.length ? current : max, "");

    // Remove tags HTML usando a função nativa do n8n
    const cleanText = longestContent.removeTags();

    // Conta a quantidade de palavras no conteúdo limpo
    const wordCount = cleanText.trim().split(/\s+/).length;

    // Retorna verdadeiro se o conteúdo tem menos de 200 palavras, falso caso contrário
    return wordCount < minWords;
  })()
}}

