    // Função para contar palavras no conteúdo
    const countWords = (text) => text ? text.trim().split(/\s+/).length : 0;

    // Conta o número de palavras no conteúdo
    const wordCount = countWords(content);

    // Define o número médio de palavras por subtítulo
    const wordsPerSubtitle = 250;

    // Calcula a quantidade de subtítulos (mínimo de 1)
    const subtitleCount = Math.max(1, Math.round(wordCount / wordsPerSubtitle));

    // Se o post for curto, criar apenas 1 subtítulo
    if (isShortPost) {
      return "- Create an array with only 1 subtitle that covers all reference content.";
    } 

    // Se for longo, usar o número dinâmico de subtítulos
    return `- Create an array with ${subtitleCount} distinct subtitles for the post that covers all the reference content.`;
  })()
}}

