// Obter os valores das variáveis
const bancoDeImagem = $node["variaveis"].json["Banco de imagem"];
const imagemNoSubtitulo = $node["variaveis"].json["Imagem no subtítulo?"];
const urlDoSite = $node["variaveis"].json["URL do Site"];
const postStatus = $node["variaveis"].json["Post Status"]; // Nova variável

// Lista de valores permitidos para 'Banco de imagem'
const valoresPermitidosBanco = [
    'Dall-e',
    'Flux',
    'LeonardoAI',
    'Midjourney',
    'Pollinations',
    'Freepik',
    'Fonte',
    'Reconhecimento',
    'Sem imagem'
];

// Lista de valores permitidos para 'Imagem no subtítulo?'
const valoresPermitidosImagem = [
    'NÃO',
    'SIM, mas intercalando',
    'SIM em Todos'
];

// Lista de valores permitidos para 'Post Status'
const valoresPermitidosPostStatus = [
    'Publicado',
    'Rascunho'
];

// Regex para validar o formato básico da URL (genérico, sem restrição de domínios)
const regexUrlValida = /^https:\/\/[a-zA-Z0-9.-]+(?:\/.*)?$/;

// 1. Validar 'Banco de imagem'
if (!valoresPermitidosBanco.includes(bancoDeImagem)) {
    throw new Error(`O valor fornecido para "Banco de imagem" é inválido. Deve ser um dos seguintes: ${valoresPermitidosBanco.join(', ')}. Valor recebido: "${bancoDeImagem}".`);
}

// 2. Validar casos específicos de 'Fonte' e 'Reconhecimento'
if (
    (bancoDeImagem === 'Fonte' || bancoDeImagem === 'Reconhecimento') &&
    imagemNoSubtitulo !== 'NÃO'
) {
    throw new Error(`Bancos de Dados "Fonte" e "Reconhecimento" não podem ser usados com imagens nos subtítulos.`);
}

// 3. Validar 'Imagem no subtítulo?'
if (!valoresPermitidosImagem.includes(imagemNoSubtitulo)) {
    throw new Error(`O valor fornecido para "Imagem no subtítulo?" é inválido. Deve ser um dos seguintes: ${valoresPermitidosImagem.join(', ')}. Valor recebido: "${imagemNoSubtitulo}".`);
}

// 4. Validar 'URL do Site'

// Verificar se a URL começa com "https://"
if (!urlDoSite.startsWith("https://")) {
    throw new Error(`A URL fornecida deve começar com "https://". Valor recebido: "${urlDoSite}".`);
}

// Verificar se a URL termina com uma barra "/"
if (urlDoSite.endsWith("/")) {
    throw new Error(`A URL fornecida não deve terminar com uma barra "/". Certifique-se de remover a barra no final. Exemplo válido: "https://blog.automacaosemlimites.com.br". Valor recebido: "${urlDoSite}".`);
}

// Verificar se a URL está no formato válido
if (!regexUrlValida.test(urlDoSite)) {
    throw new Error(`A URL fornecida está inválida. Certifique-se de que segue o formato padrão como no exemplo: "https://blog.automacaosemlimites.com.br". Valor recebido: "${urlDoSite}".`);
}

// 5. Validar 'Post Status'
if (!valoresPermitidosPostStatus.includes(postStatus)) {
    throw new Error(`O valor fornecido para "Post Status" é inválido. Deve ser "Publicado" ou "Rascunho". Valor recebido: "${postStatus}".`);
}

// 6. Validar se "Banco de imagem" for vazio ou "Sem imagem", então "Imagem no subtítulo?" deve ser "NÃO"
if ((!bancoDeImagem || bancoDeImagem === 'Sem imagem') && imagemNoSubtitulo !== 'NÃO') {
    throw new Error(`Quando o "Banco de imagem" estiver vazio ou for "Sem imagem", a opção "Imagem no subtítulo?" deve ser "NÃO". Valor recebido: "${imagemNoSubtitulo}".`);
}



// Retornar os dados normalmente se nenhuma condição de erro for atendida
return $node["variaveis"].json;

